package com.samudhra.certificates.entity;
import jakarta.persistence.*;
@Entity @Table(name="uploads", indexes=@Index(columnList="organization_id")) public class Upload extends BaseEntity {
  @ManyToOne(fetch=FetchType.LAZY,optional=false) private Organization organization; @ManyToOne(fetch=FetchType.LAZY,optional=false) private User uploadedBy; @Column(nullable=false) private String purpose; @Column(nullable=false) private String storedName; @Column(nullable=false) private String originalName; @Column(nullable=false) private String contentType; private long size; @Column(nullable=false,unique=true) private String url;
  public Organization getOrganization(){return organization;} public void setOrganization(Organization v){organization=v;} public User getUploadedBy(){return uploadedBy;} public void setUploadedBy(User v){uploadedBy=v;} public String getPurpose(){return purpose;} public void setPurpose(String v){purpose=v;} public String getStoredName(){return storedName;} public void setStoredName(String v){storedName=v;} public String getOriginalName(){return originalName;} public void setOriginalName(String v){originalName=v;} public String getContentType(){return contentType;} public void setContentType(String v){contentType=v;} public long getSize(){return size;} public void setSize(long v){size=v;} public String getUrl(){return url;} public void setUrl(String v){url=v;}
}
